  5→//! Notch command - JJ-aware commit with heat/pace context prefix
  6→//!
  7→//! This module handles the jjx_notch command which performs a staged commit
  8→//! with heat/pace context prefix. It accepts explicit file list and generates
  9→//! a JJ context-aware commit message.
 10→
 11→use clap::Args;
 12→use std::collections::HashSet;
 13→use std::process::Command;
 14→
 15→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark, JJRF_FIREMARK_PREFIX, JJRF_CORONET_PREFIX};
 16→use crate::jjrn_notch::{jjrn_format_notch_prefix, JJRN_COMMIT_PREFIX};
 17→
 18→/// Arguments for jjx_notch command
 19→#[derive(Args, Debug)]
 20→pub struct jjrnc_NotchArgs {
 21→    /// Identity: Coronet (5-char, pace-affiliated) or Firemark (2-char, heat-only)
 22→    pub identity: String,
 23→
 24→    /// Files to commit (required, at least one)
 25→    #[arg(required = true)]
 26→    pub files: Vec<String>,
 27→
 28→    /// Size limit in bytes (overrides default 50KB guard)
 29→    #[arg(long)]
 30→    pub size_limit: Option<u64>,
 31→
 32→    /// User-provided commit message intent (overrides haiku-generated message)
 33→    #[arg(long)]
 34→    pub intent: Option<String>,
 35→}
 36→
 37→/// Run the notch command
 38→///
 39→/// Stages specified files and commits with JJ-aware prefix.
 40→/// Supports both pace-affiliated (Coronet) and heat-only (Firemark) commits.
 41→pub fn jjrnc_run_notch(args: jjrnc_NotchArgs) -> i32 {
 42→    // Require non-empty files list
 43→    if args.files.is_empty() {
 44→        eprintln!("jjx_notch: error: at least one file required");
 45→        return 1;
 46→    }
 47→
 48→    // Check each file either exists on disk or is tracked by git (for deletions)
 49→    for file in &args.files {
 50→        let path_exists = std::path::Path::new(file).exists();
 51→
 52→        // If file doesn't exist on disk, check if it's tracked by git
 53→        if !path_exists {
 54→            let git_ls_output = match Command::new("git")
 55→                .args(["ls-files", "--error-unmatch", file])
 56→                .output()
 57→            {
 58→                Ok(o) => o,
 59→                Err(e) => {
 60→                    eprintln!("jjx_notch: error: failed to check git tracking: {}", e);
 61→                    return 1;
 62→                }
 63→            };
 64→
 65→            // If git ls-files fails, check if it's a staged deletion
 66→            if !git_ls_output.status.success() {
 67→                let git_diff_output = match Command::new("git")
 68→                    .args(["diff", "--cached", "--name-only", "--diff-filter=D", "--", file])
 69→                    .output()
 70→                {
 71→                    Ok(o) => o,
 72→                    Err(e) => {
 73→                        eprintln!("jjx_notch: error: failed to check staged deletion: {}", e);
 74→                        return 1;
 75→                    }
 76→                };
 77→
 78→                // If diff output is non-empty, file is a staged deletion - accept it
 79→                let is_staged_deletion = git_diff_output.status.success()
 80→                    && !git_diff_output.stdout.is_empty();
 81→
 82→                if !is_staged_deletion {
 83→                    eprintln!("jjx_notch: error: file does not exist and is not tracked by git: {}", file);
 84→                    return 1;
 85→                }
 86→            }
 87→        }
 88→    }
 89→
 90→    // Parse identity - support both Coronet (5 chars) and Firemark (2 chars)
 91→    let identity = args.identity.strip_prefix(JJRF_CORONET_PREFIX).or_else(|| args.identity.strip_prefix(JJRF_FIREMARK_PREFIX)).unwrap_or(&args.identity);
 92→
 93→    let message = if identity.len() == 5 {
 94→        // Coronet - pace-affiliated commit
 95→        let coronet = match Coronet::jjrf_parse(&args.identity) {
 96→            Ok(c) => c,
 97→            Err(e) => {
 98→                eprintln!("jjx_notch: error: {}", e);
 99→                return 1;
100→            }
101→        };
102→        jjrn_format_notch_prefix(&coronet)
103→    } else if identity.len() == 2 {
104→        // Firemark - heat-only commit
105→        let firemark = match Firemark::jjrf_parse(&args.identity) {
106→            Ok(fm) => fm,
107→            Err(e) => {
108→                eprintln!("jjx_notch: error: {}", e);
109→                return 1;
110→            }
111→        };
112→        let hallmark = vvc::vvcc_get_hallmark();
113→        let identity_str = format!("{}{}", JJRF_FIREMARK_PREFIX, firemark.jjrf_as_str());
114→        vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity_str, "n", "", None)
115→    } else {
116→        eprintln!("jjx_notch: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
117→        return 1;
118→    };
119→
120→    // Warn about uncommitted changes outside the file list
121→    let output = match Command::new("git")
122→        .args(["status", "--porcelain"])
123→        .output()
124→    {
125→        Ok(o) => o,
126→        Err(e) => {
127→            eprintln!("jjx_notch: error: failed to run git status: {}", e);
128→            return 1;
129→        }
130→    };
131→
132→    if !output.status.success() {
133→        eprintln!("jjx_notch: error: git status failed");
134→        return 1;
135→    }
136→
137→    let status_output = String::from_utf8_lossy(&output.stdout);
138→    let files_set: HashSet<_> = args.files.iter().map(|s| s.as_str()).collect();
139→    let mut warnings = Vec::new();
140→
141→    for line in status_output.lines() {
142→        if line.len() < 4 {
143→            continue;
144→        }
145→        // Parse git status --porcelain format: "XY filename"
146→        let filepath = &line[3..];
147→        if !files_set.contains(filepath) {
148→            warnings.push(format!("  {}", line));
149→        }
150→    }
151→
152→    if !warnings.is_empty() {
153→        eprintln!("warning: uncommitted changes outside file list:");
154→        for warning in warnings {
155→            eprintln!("{}", warning);
156→        }
157→    }
158→
159→    // Stage only the specified files
160→    let mut git_add = Command::new("git");
161→    git_add.arg("add");
162→    for file in &args.files {
163→        git_add.arg(file);
164→    }
165→
166→    let add_output = match git_add.output() {
167→        Ok(o) => o,
168→        Err(e) => {
169→            eprintln!("jjx_notch: error: failed to run git add: {}", e);
170→            return 1;
171→        }
172→    };
173→
174→    if !add_output.status.success() {
175→        eprintln!("jjx_notch: error: git add failed");
176→        return 1;
177→    }
178→
179→    // Commit using vvc with the generated message prefix
180→    // If --intent provided, use it as the message; otherwise let haiku generate it
181→    let commit_args = if let Some(intent) = args.intent {
182→        vvc::vvcc_CommitArgs {
183→            prefix: None,
184→            message: Some(format!("{}{}", message, intent)),
185→            allow_empty: false,
186→            no_stage: true,  // We already staged above
187→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
188→            warn_limit: vvc::VVCG_WARN_LIMIT,
189→        }
190→    } else {
191→        vvc::vvcc_CommitArgs {
192→            prefix: Some(message),
193→            message: None,
194→            allow_empty: false,
195→            no_stage: true,  // We already staged above
196→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
197→            warn_limit: vvc::VVCG_WARN_LIMIT,
198→        }
199→    };
200→
201→    vvc::commit(&commit_args)
202→}
