 5→//! Landing command - record agent landing after autonomous execution
 6→//!
 7→//! The landing command creates an empty commit recording when an autonomous agent
 8→//! completes execution of a bridled pace. The commit message uses the L (landing)
 9→//! marker in the steeplechase format.
10→
11→use clap::Args;
12→use crate::jjrf_favor::jjrf_Coronet as Coronet;
13→use crate::jjrn_notch::jjrn_format_landing_message;
14→
15→/// Arguments for jjx_landing command
16→#[derive(Args, Debug)]
17→pub struct jjrld_LandingArgs {
18→    /// Pace identity (Coronet)
19→    pub coronet: String,
20→
21→    /// Agent tier that executed the pace
22→    pub agent: String,
23→}
24→
25→/// Execute the landing command
26→///
27→/// Creates an empty commit with L marker recording when an agent completes
28→/// execution of a bridled pace. Content is the agent completion report.
29→///
30→/// Returns exit code (0 for success, non-zero for failure).
31→pub fn jjrld_run_landing(args: jjrld_LandingArgs, content: String) -> i32 {
32→    // Parse coronet
33→    let coronet = match Coronet::jjrf_parse(&args.coronet) {
34→        Ok(c) => c,
35→        Err(e) => {
36→            eprintln!("jjx_landing: error: {}", e);
37→            return 1;
38→        }
39→    };
40→
41→    // Use jjrn_format_landing_message to create the commit message, with content as body
42→    let base_message = jjrn_format_landing_message(&coronet, &args.agent);
43→    let message = if content.trim().is_empty() {
44→        base_message
45→    } else {
46→        format!("{}\n\n{}", base_message, content.trim())
47→    };
48→
49→    // Create empty landing commit
50→    let commit_args = vvc::vvcc_CommitArgs {
51→        prefix: None,
52→        message: Some(message),
53→        allow_empty: true,
54→        no_stage: true,
55→        size_limit: vvc::VVCG_SIZE_LIMIT,
56→        warn_limit: vvc::VVCG_WARN_LIMIT,
57→    };
58→
59→    vvc::commit(&commit_args)
60→}
