  5→//! Notch command - JJ-aware commit with heat/pace context prefix
  6→//!
  7→//! This module handles the jjx_notch command which performs a staged commit
  8→//! with heat/pace context prefix. It accepts explicit file list and generates
  9→//! a JJ context-aware commit message.
 10→
 11→use clap::Args;
 12→use std::collections::HashSet;
 13→use std::process::Command;
 14→
 15→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark, JJRF_FIREMARK_PREFIX, JJRF_CORONET_PREFIX};
 16→use crate::jjrn_notch::{jjrn_format_notch_prefix, JJRN_COMMIT_PREFIX};
 17→
 18→/// Arguments for jjx_notch command
 19→#[derive(Args, Debug)]
 20→pub struct jjrnc_NotchArgs {
 21→    /// Identity: Coronet (5-char, pace-affiliated) or Firemark (2-char, heat-only)
 22→    pub identity: String,
 23→
 24→    /// Files to commit (required, at least one)
 25→    #[arg(required = true)]
 26→    pub files: Vec<String>,
 27→
 28→    /// Size limit in bytes (overrides default 50KB guard)
 29→    #[arg(long)]
 30→    pub size_limit: Option<u64>,
 31→
 32→    /// User-provided commit message intent (overrides haiku-generated message)
 33→    #[arg(long)]
 34→    pub intent: Option<String>,
 35→}
 36→
 37→/// Run the notch command
 38→///
 39→/// Stages specified files and commits with JJ-aware prefix.
 40→/// Supports both pace-affiliated (Coronet) and heat-only (Firemark) commits.
 41→pub fn jjrnc_run_notch(args: jjrnc_NotchArgs) -> (i32, String) {
 42→    let buf = String::new();
 43→
 44→    // Require non-empty files list
 45→    if args.files.is_empty() {
 46→        eprintln!("jjx_notch: error: at least one file required");
 47→        return (1, buf);
 48→    }
 49→
 50→    // Check each file either exists on disk or is tracked by git (for deletions)
 51→    for file in &args.files {
 52→        let path_exists = std::path::Path::new(file).exists();
 53→
 54→        // If file doesn't exist on disk, check if it's tracked by git
 55→        if !path_exists {
 56→            let git_ls_output = match Command::new("git")
 57→                .args(["ls-files", "--error-unmatch", file])
 58→                .output()
 59→            {
 60→                Ok(o) => o,
 61→                Err(e) => {
 62→                    eprintln!("jjx_notch: error: failed to check git tracking: {}", e);
 63→                    return (1, buf);
 64→                }
 65→            };
 66→
 67→            // If git ls-files fails, check if it's a staged deletion
 68→            if !git_ls_output.status.success() {
 69→                let git_diff_output = match Command::new("git")
 70→                    .args(["diff", "--cached", "--name-only", "--diff-filter=D", "--", file])
 71→                    .output()
 72→                {
 73→                    Ok(o) => o,
 74→                    Err(e) => {
 75→                        eprintln!("jjx_notch: error: failed to check staged deletion: {}", e);
 76→                        return (1, buf);
 77→                    }
 78→                };
 79→
 80→                // If diff output is non-empty, file is a staged deletion - accept it
 81→                let is_staged_deletion = git_diff_output.status.success()
 82→                    && !git_diff_output.stdout.is_empty();
 83→
 84→                if !is_staged_deletion {
 85→                    eprintln!("jjx_notch: error: file does not exist and is not tracked by git: {}", file);
 86→                    return (1, buf);
 87→                }
 88→            }
 89→        }
 90→    }
 91→
 92→    // Parse identity - support both Coronet (5 chars) and Firemark (2 chars)
 93→    let identity = args.identity.strip_prefix(JJRF_CORONET_PREFIX).or_else(|| args.identity.strip_prefix(JJRF_FIREMARK_PREFIX)).unwrap_or(&args.identity);
 94→
 95→    let message = if identity.len() == 5 {
 96→        // Coronet - pace-affiliated commit
 97→        let coronet = match Coronet::jjrf_parse(&args.identity) {
 98→            Ok(c) => c,
 99→            Err(e) => {
100→                eprintln!("jjx_notch: error: {}", e);
101→                return (1, buf);
102→            }
103→        };
104→        jjrn_format_notch_prefix(&coronet)
105→    } else if identity.len() == 2 {
106→        // Firemark - heat-only commit
107→        let firemark = match Firemark::jjrf_parse(&args.identity) {
108→            Ok(fm) => fm,
109→            Err(e) => {
110→                eprintln!("jjx_notch: error: {}", e);
111→                return (1, buf);
112→            }
113→        };
114→        let hallmark = vvc::vvcc_get_hallmark();
115→        let identity_str = format!("{}{}", JJRF_FIREMARK_PREFIX, firemark.jjrf_as_str());
116→        vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity_str, "n", "", None)
117→    } else {
118→        eprintln!("jjx_notch: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
119→        return (1, buf);
120→    };
121→
122→    // Warn about uncommitted changes outside the file list
123→    let output = match Command::new("git")
124→        .args(["status", "--porcelain"])
125→        .output()
126→    {
127→        Ok(o) => o,
128→        Err(e) => {
129→            eprintln!("jjx_notch: error: failed to run git status: {}", e);
130→            return (1, buf);
131→        }
132→    };
133→
134→    if !output.status.success() {
135→        eprintln!("jjx_notch: error: git status failed");
136→        return (1, buf);
137→    }
138→
139→    let status_output = String::from_utf8_lossy(&output.stdout);
140→    let files_set: HashSet<_> = args.files.iter().map(|s| s.as_str()).collect();
141→    let mut warnings = Vec::new();
142→
143→    for line in status_output.lines() {
144→        if line.len() < 4 {
145→            continue;
146→        }
147→        // Parse git status --porcelain format: "XY filename"
148→        let filepath = &line[3..];
149→        if !files_set.contains(filepath) {
150→            warnings.push(format!("  {}", line));
151→        }
152→    }
153→
154→    if !warnings.is_empty() {
155→        eprintln!("warning: uncommitted changes outside file list:");
156→        for warning in warnings {
157→            eprintln!("{}", warning);
158→        }
159→    }
160→
161→    // Stage only the specified files
162→    let mut git_add = Command::new("git");
163→    git_add.arg("add");
164→    for file in &args.files {
165→        git_add.arg(file);
166→    }
167→
168→    let add_output = match git_add.output() {
169→        Ok(o) => o,
170→        Err(e) => {
171→            eprintln!("jjx_notch: error: failed to run git add: {}", e);
172→            return (1, buf);
173→        }
174→    };
175→
176→    if !add_output.status.success() {
177→        eprintln!("jjx_notch: error: git add failed");
178→        return (1, buf);
179→    }
180→
181→    // Commit using vvc with the generated message prefix
182→    // If --intent provided, use it as the message; otherwise let haiku generate it
183→    let commit_args = if let Some(intent) = args.intent {
184→        vvc::vvcc_CommitArgs {
185→            prefix: None,
186→            message: Some(format!("{}{}", message, intent)),
187→            allow_empty: false,
188→            no_stage: true,  // We already staged above
189→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
190→            warn_limit: vvc::VVCG_WARN_LIMIT,
191→        }
192→    } else {
193→        vvc::vvcc_CommitArgs {
194→            prefix: Some(message),
195→            message: None,
196→            allow_empty: false,
197→            no_stage: true,  // We already staged above
198→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
199→            warn_limit: vvc::VVCG_WARN_LIMIT,
200→        }
201→    };
202→
203→    let rc = vvc::commit(&commit_args);
204→    (rc, buf)
205→}
206→

