  5→//! Wrap command - mark a pace complete with automated commit
  6→//!
  7→//! Stages all changes, generates a commit message with Claude,
  8→//! and transitions the pace state to complete with chalk marker.
  9→
 10→use std::path::PathBuf;
 11→use std::process::Command;
 12→use std::io::Write;
 13→use std::fmt::Write as FmtWrite;
 14→
 15→use crate::jjrf_favor::{jjrf_Coronet as Coronet};
 16→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_TallyArgs as LibTallyArgs, jjrg_PaceState};
 17→use crate::jjrn_notch::{jjrn_ChalkMarker, jjrn_format_notch_prefix, jjrn_format_chalk_message};
 18→
 19→/// Arguments for jjx_wrap command
 20→#[derive(clap::Args, Debug)]
 21→pub struct jjrx_WrapArgs {
 22→    /// Pace identity (Coronet)
 23→    pub coronet: String,
 24→
 25→    /// Size limit in bytes (overrides default 50KB guard)
 26→    #[arg(long)]
 27→    pub size_limit: Option<u64>,
 28→}
 29→
 30→/// Helper to get pace silks or return default message
 31→fn get_pace_silks_or_default(gallops: &Gallops, firemark_key: &str, coronet_key: &str) -> String {
 32→    gallops.heats
 33→        .get(firemark_key)
 34→        .and_then(|heat| heat.paces.get(coronet_key))
 35→        .and_then(|pace| pace.tacks.first())
 36→        .map(|tack| format!("pace {} complete", tack.silks))
 37→        .unwrap_or_else(|| "pace complete".to_string())
 38→}
 39→
 40→/// Execute wrap command - mark pace complete with commit
 41→///
 42→/// Stages all changes, checks size, generates commit message using Claude,
 43→/// creates the work commit, then transitions pace to complete state with
 44→/// chalk marker commit.
 45→///
 46→/// Returns exit code (0 for success, non-zero for failure).
 47→pub fn zjjrx_run_wrap(args: jjrx_WrapArgs, summary: Option<String>) -> (i32, String) {
 48→    let mut buf = String::new();
 49→
 50→    // Parse coronet
 51→    let coronet = match Coronet::jjrf_parse(&args.coronet) {
 52→        Ok(c) => c,
 53→        Err(e) => {
 54→            eprintln!("jjx_wrap: error: {}", e);
 55→            return (1, buf);
 56→        }
 57→    };
 58→
 59→    let stdin_summary = summary;
 60→
 61→    // Acquire commit lock
 62→    let _lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 63→        Ok(l) => l,
 64→        Err(e) => {
 65→            eprintln!("jjx_wrap: error: {}", e);
 66→            return (1, buf);
 67→        }
 68→    };
 69→
 70→    // Stage all changes
 71→    let add_output = match Command::new("git")
 72→        .args(["add", "-A"])
 73→        .output()
 74→    {
 75→        Ok(o) => o,
 76→        Err(e) => {
 77→            eprintln!("jjx_wrap: error: failed to run git add: {}", e);
 78→            return (1, buf);
 79→        }
 80→    };
 81→
 82→    if !add_output.status.success() {
 83→        eprintln!("jjx_wrap: error: git add failed");
 84→        return (1, buf);
 85→    }
 86→
 87→    // Size guard check
 88→    let size_limit = args.size_limit.unwrap_or(50000); // 50KB default
 89→    let diff_output = match Command::new("git")
 90→        .args(["diff", "--cached", "--stat"])
 91→        .output()
 92→    {
 93→        Ok(o) => o,
 94→        Err(e) => {
 95→            eprintln!("jjx_wrap: error: failed to run git diff: {}", e);
 96→            return (1, buf);
 97→        }
 98→    };
 99→
100→    if !diff_output.status.success() {
101→        eprintln!("jjx_wrap: error: git diff failed");
102→        return (1, buf);
103→    }
104→
105→    // Parse size from last line of --stat output (format: "N files changed, M insertions(+), K deletions(-)")
106→    // Better size check: get actual staged content size
107→    let numstat_output = match Command::new("git")
108→        .args(["diff", "--cached", "--numstat"])
109→        .output()
110→    {
111→        Ok(o) => o,
112→        Err(e) => {
113→            eprintln!("jjx_wrap: error: failed to run git diff --numstat: {}", e);
114→            return (1, buf);
115→        }
116→    };
117→
118→    if !numstat_output.status.success() {
119→        eprintln!("jjx_wrap: error: git diff --numstat failed");
120→        return (1, buf);
121→    }
122→
123→    let numstat_str = String::from_utf8_lossy(&numstat_output.stdout);
124→    let mut total_size: u64 = 0;
125→    for line in numstat_str.lines() {
126→        let parts: Vec<&str> = line.split_whitespace().collect();
127→        if parts.len() >= 2 {
128→            // Format: added\tdeleted\tfilename
129→            if let Ok(added) = parts[0].parse::<u64>() {
130→                total_size += added;
131→            }
132→            if let Ok(deleted) = parts[1].parse::<u64>() {
133→                total_size += deleted;
134→            }
135→        }
136→    }
137→
138→    if total_size > size_limit {
139→        eprintln!("jjx_wrap: error: staged changes exceed size limit ({} > {} bytes)", total_size, size_limit);
140→        // Lock released automatically by Drop
141→        return (2, buf);
142→    }
143→
144→    // Check if there are staged changes to commit
145→    let has_staged_changes = !numstat_str.trim().is_empty();
146→
147→    // Only generate commit message and commit if there are staged changes
148→    let commit_hash = if has_staged_changes {
149→        // Generate commit message using Claude CLI
150→        let diff_content = match Command::new("git")
151→            .args(["diff", "--cached"])
152→            .output()
153→        {
154→            Ok(o) => o,
155→            Err(e) => {
156→                eprintln!("jjx_wrap: error: failed to run git diff --cached: {}", e);
157→                return (1, buf);
158→            }
159→        };
160→
161→        if !diff_content.status.success() {
162→            eprintln!("jjx_wrap: error: git diff --cached failed");
163→            return (1, buf);
164→        }
165→
166→        let mut claude_cmd = match vvc::vvce_claude_command()
167→            .args([
168→                "--print",
169→                &format!("Generate a concise commit message for this diff. The commit wraps pace {}. Output only the message, no quotes.", args.coronet)
170→            ])
171→            .stdin(std::process::Stdio::piped())
172→            .stdout(std::process::Stdio::piped())
173→            .stderr(std::process::Stdio::piped())
174→            .spawn()
175→        {
176→            Ok(c) => c,
177→            Err(e) => {
178→                eprintln!("jjx_wrap: error: failed to spawn claude command: {}", e);
179→                return (1, buf);
180→            }
181→        };
182→
183→        // Write diff to stdin
184→        if let Some(mut stdin) = claude_cmd.stdin.take() {
185→            if let Err(e) = stdin.write_all(&diff_content.stdout) {
186→                eprintln!("jjx_wrap: error: failed to write to claude stdin: {}", e);
187→                return (1, buf);
188→            }
189→        }
190→
191→        let claude_output = match claude_cmd.wait_with_output() {
192→            Ok(o) => o,
193→            Err(e) => {
194→                eprintln!("jjx_wrap: error: failed to wait for claude: {}", e);
195→                return (1, buf);
196→            }
197→        };
198→
199→        if !claude_output.status.success() {
200→            eprintln!("jjx_wrap: error: claude command failed");
201→            eprintln!("{}", String::from_utf8_lossy(&claude_output.stderr));
202→            return (1, buf);
203→        }
204→
205→        let generated_message = String::from_utf8_lossy(&claude_output.stdout).trim().to_string();
206→
207→        // Commit with git directly (already staged via git add -A)
208→        let prefix = jjrn_format_notch_prefix(&coronet);
209→        let full_message = format!("{}{}\n\nCo-Authored-By: Claude <noreply@anthropic.com>", prefix, generated_message);
210→
211→        let commit_output = match Command::new("git")
212→            .args(["commit", "-m", &full_message])
213→            .output()
214→        {
215→            Ok(o) => o,
216→            Err(e) => {
217→                eprintln!("jjx_wrap: error: failed to run git commit: {}", e);
218→                return (1, buf);
219→            }
220→        };
221→
222→        if !commit_output.status.success() {
223→            eprintln!("jjx_wrap: error: git commit failed");
224→            eprintln!("{}", String::from_utf8_lossy(&commit_output.stderr));
225→            return (1, buf);
226→        }
227→
228→        // Get commit hash
229→        let hash_output = match Command::new("git")
230→            .args(["rev-parse", "HEAD"])
231→            .output()
232→        {
233→            Ok(o) => o,
234→            Err(e) => {
235→                eprintln!("jjx_wrap: error: failed to get commit hash: {}", e);
236→                return (1, buf);
237→            }
238→        };
239→
240→        String::from_utf8_lossy(&hash_output.stdout).trim().to_string()
241→    } else {
242→        // No staged changes - this is valid for verification-only paces
243→        eprintln!("jjx_wrap: no staged changes, proceeding with state transition only");
244→
245→        // Get current HEAD as reference (no new work commit created)
246→        let hash_output = match Command::new("git")
247→            .args(["rev-parse", "HEAD"])
248→            .output()
249→        {
250→            Ok(o) => o,
251→            Err(e) => {
252→                eprintln!("jjx_wrap: error: failed to get commit hash: {}", e);
253→                return (1, buf);
254→            }
255→        };
256→
257→        String::from_utf8_lossy(&hash_output.stdout).trim().to_string()
258→    };
259→
260→    // Transition pace state to complete
261→    let gallops_path = PathBuf::from(".claude/jjm/jjg_gallops.json");
262→    let mut gallops = match Gallops::jjrg_load(&gallops_path) {
263→        Ok(g) => g,
264→        Err(e) => {
265→            eprintln!("jjx_wrap: error loading Gallops: {}", e);
266→            return (1, buf);
267→        }
268→    };
269→
270→    let tally_args = LibTallyArgs {
271→        coronet: args.coronet.clone(),
272→        state: Some(jjrg_PaceState::Complete),
273→        direction: None,
274→        text: None,
275→        silks: None,
276→    };
277→
278→    if let Err(e) = gallops.jjrg_tally(tally_args) {
279→        eprintln!("jjx_wrap: error: {}", e);
280→        return (1, buf);
281→    }
282→
283→    // Save gallops
284→    if let Err(e) = gallops.jjrg_save(&gallops_path) {
285→        eprintln!("jjx_wrap: error saving Gallops: {}", e);
286→        return (1, buf);
287→    }
288→
289→    // Build chalk description: use stdin if provided, else "pace {silks} complete"
290→    let firemark = coronet.jjrf_parent_firemark();
291→    let firemark_key = firemark.jjrf_display();
292→    let coronet_key = coronet.jjrf_display();
293→
294→    let chalk_description = if let Some(ref text) = stdin_summary {
295→        let trimmed = text.trim();
296→        if !trimmed.is_empty() {
297→            trimmed.to_string()
298→        } else {
299→            // Empty stdin - use default with silks
300→            get_pace_silks_or_default(&gallops, &firemark_key, &coronet_key)
301→        }
302→    } else {
303→        // No stdin - use default with silks
304→        get_pace_silks_or_default(&gallops, &firemark_key, &coronet_key)
305→    };
306→
307→    // Create W chalk marker commit with gallops state change
308→    let chalk_message = jjrn_format_chalk_message(&coronet, jjrn_ChalkMarker::Wrap, &chalk_description);
309→
310→    let chalk_commit_args = vvc::vvcm_CommitArgs {
311→        files: vec![".claude/jjm/jjg_gallops.json".to_string()],
312→        message: chalk_message,
313→        size_limit: vvc::VVCG_SIZE_LIMIT,
314→        warn_limit: vvc::VVCG_WARN_LIMIT,
315→    };
316→
317→    match vvc::machine_commit(&_lock, &chalk_commit_args) {
318→        Ok(_) => {
319→            let _ = writeln!(buf, "{}", commit_hash);
320→            let fm = coronet.jjrf_parent_firemark();
321→            let fm_key = fm.jjrf_display();
322→            let fm_str = fm.jjrf_as_str();
323→
324→            // Lookahead: find next actionable pace in this heat
325→            let next_pace_info = gallops.heats.get(&fm_key).and_then(|heat| {
326→                heat.order.iter().find_map(|c| {
327→                    heat.paces.get(c.as_str()).and_then(|pace| {
328→                        pace.tacks.first().and_then(|tack| {
329→                            match tack.state {
330→                                jjrg_PaceState::Rough | jjrg_PaceState::Bridled => {
331→                                    Some((c.clone(), tack.silks.clone()))
332→                                }
333→                                _ => None,
334→                            }
335→                        })
336→                    })
337→                })
338→            });
339→
340→            eprintln!();
341→            match next_pace_info {
342→                Some((next_coronet, next_silks)) => {
343→                    eprintln!("AGENT_RESPONSE: \u{20a2}{} wrapped. Next: {} (\u{20a2}{}) \u{2014} `/clear` then `/jjc-heat-mount {}`",
344→                        args.coronet, next_silks, next_coronet, fm_str);
345→                }
346→                None => {
347→                    eprintln!("AGENT_RESPONSE: \u{20a2}{} wrapped. All paces complete \u{2014} `/clear` then `/jjc-heat-retire {}`",
348→                        args.coronet, fm_str);
349→                }
350→            }
351→            (0, buf)
352→        }
353→        Err(e) => {
354→            eprintln!("jjx_wrap: error: chalk commit failed: {}", e);
355→            eprintln!("jjx_wrap: warning: gallops state updated but not committed");
356→            (1, buf)
357→        }
358→    }
359→    // lock released here
360→}
