 5→//! Curry command - paddock update operation for Heat context
 6→//!
 7→//! Supports getter mode (display paddock) and setter mode (update with chalk entry).
 8→
 9→use std::fmt::Write;
10→use std::path::PathBuf;
11→use crate::jjrf_favor::{jjrf_Firemark as Firemark};
12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops};
13→
14→/// Arguments for jjx_curry command
15→#[derive(clap::Args, Debug)]
16→pub struct jjrcu_CurryArgs {
17→    /// Path to the Gallops JSON file
18→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
19→    pub file: PathBuf,
20→
21→    /// Target Heat identity (Firemark)
22→    pub firemark: String,
23→
24→    /// Optional note for chalk entry
25→    #[arg(long)]
26→    pub note: Option<String>,
27→}
28→
29→/// Handler for jjx_curry command
30→pub fn jjrcu_run_curry(args: jjrcu_CurryArgs, content: Option<String>) -> (i32, String) {
31→    use crate::jjro_ops::jjrg_curry;
32→
33→    let mut buf = String::new();
34→
35→    // Parse firemark
36→    let firemark = match Firemark::jjrf_parse(&args.firemark) {
37→        Ok(fm) => fm,
38→        Err(e) => {
39→            eprintln!("jjx_curry: error: {}", e);
40→            return (1, buf);
41→        }
42→    };
43→
44→    match content {
45→        None => {
46→            // Getter mode: display paddock content
47→            let gallops = match Gallops::jjrg_load(&args.file) {
48→                Ok(g) => g,
49→                Err(e) => {
50→                    eprintln!("jjx_curry: error loading Gallops: {}", e);
51→                    return (1, buf);
52→                }
53→            };
54→
55→            let firemark_key = firemark.jjrf_display();
56→            let heat = match gallops.heats.get(&firemark_key) {
57→                Some(h) => h,
58→                None => {
59→                    eprintln!("jjx_curry: error: Heat '{}' not found", firemark_key);
60→                    return (1, buf);
61→                }
62→            };
63→
64→            let paddock_path = std::path::Path::new(&heat.paddock_file);
65→            let content = match std::fs::read_to_string(paddock_path) {
66→                Ok(c) => c,
67→                Err(e) => {
68→                    eprintln!("jjx_curry: error reading paddock: {}", e);
69→                    return (1, buf);
70→                }
71→            };
72→
73→            let _ = write!(buf, "{}", content);
74→            (0, buf)
75→        }
76→        Some(new_content) => {
77→            // Setter mode: update paddock
78→            // Call operation (curry acquires its own lock)
79→            match jjrg_curry(&args.file, &firemark, &new_content, args.note.as_deref()) {
80→                Ok(()) => {
81→                    eprintln!("jjx_curry: paddock updated");
82→                    (0, buf)
83→                }
84→                Err(e) => {
85→                    eprintln!("jjx_curry: error: {}", e);
86→                    (1, buf)
87→                }
88→            }
89→        }
90→    }
91→}
