  5→//! Restring command - bulk draft multiple paces between heats
  6→//!
  7→//! Handles the jjx_restring command which moves multiple paces from one heat
  8→//! to another in a single atomic operation.
  9→
 10→use std::fmt::Write;
 11→use std::path::PathBuf;
 12→
 13→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 14→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_RestringArgs as LibRestringArgs, jjrg_PaceState};
 15→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 16→
 17→/// Arguments for jjx_restring command
 18→#[derive(clap::Args, Debug)]
 19→pub struct jjrrs_RestringArgs {
 20→    /// Path to the Gallops JSON file
 21→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 22→    pub file: PathBuf,
 23→
 24→    /// Source Heat identity (Firemark)
 25→    pub firemark: String,
 26→
 27→    /// Destination Heat identity (Firemark)
 28→    #[arg(long)]
 29→    pub to: String,
 30→}
 31→
 32→/// Execute restring command - bulk draft multiple paces atomically
 33→pub fn jjrrs_run(args: jjrrs_RestringArgs, coronets: String) -> (i32, String) {
 34→    let mut buf = String::new();
 35→
 36→    // Acquire lock FIRST - fail fast if another operation is in progress
 37→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 38→        Ok(l) => l,
 39→        Err(e) => {
 40→            eprintln!("jjx_restring: error: {}", e);
 41→            return (1, buf);
 42→        }
 43→    };
 44→
 45→    let coronets: Vec<String> = match serde_json::from_str(&coronets) {
 46→        Ok(c) => c,
 47→        Err(e) => {
 48→            eprintln!("jjx_restring: error: Expected JSON array of coronets: {}", e);
 49→            return (1, buf);
 50→        }
 51→    };
 52→
 53→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 54→        Ok(g) => g,
 55→        Err(e) => {
 56→            eprintln!("jjx_restring: error loading Gallops: {}", e);
 57→            return (1, buf);
 58→        }
 59→    };
 60→
 61→    let restring_args = LibRestringArgs {
 62→        source_firemark: args.firemark.clone(),
 63→        dest_firemark: args.to.clone(),
 64→        coronets,
 65→    };
 66→
 67→    // Execute restring operation
 68→    let result = match gallops.jjrg_restring(restring_args) {
 69→        Ok(r) => r,
 70→        Err(e) => {
 71→            eprintln!("jjx_restring: error: {}", e);
 72→            return (1, buf);
 73→        }
 74→    };
 75→
 76→    // Save gallops
 77→    if let Err(e) = gallops.jjrg_save(&args.file) {
 78→        eprintln!("jjx_restring: error saving Gallops: {}", e);
 79→        return (1, buf);
 80→    }
 81→
 82→    // Parse both firemarks for commit file list
 83→    let dest_fm = Firemark::jjrf_parse(&result.dest_firemark).expect("restring returned invalid dest firemark");
 84→
 85→    let gallops_path = args.file.to_string_lossy().to_string();
 86→    let source_paddock_path = result.source_paddock.clone();
 87→    let dest_paddock_path = result.dest_paddock.clone();
 88→
 89→    // Build commit message using heat-level action
 90→    let commit_message = format_heat_message(
 91→        &dest_fm,
 92→        HeatAction::Draft,  // Reusing Draft action since this is a bulk draft operation
 93→        &format!("restring {} paces from {}", result.drafted.len(), result.source_firemark)
 94→    );
 95→
 96→    let commit_args = vvc::vvcm_CommitArgs {
 97→        files: vec![
 98→            gallops_path,
 99→            source_paddock_path,
100→            dest_paddock_path,
101→        ],
102→        message: commit_message,
103→        size_limit: 100000,  // 100KB - bulk operations can be large
104→        warn_limit: 50000,
105→    };
106→
107→    match vvc::machine_commit(&lock, &commit_args) {
108→        Ok(hash) => {
109→            eprintln!("jjx_restring: committed {}", &hash[..8]);
110→        }
111→        Err(e) => {
112→            eprintln!("jjx_restring: commit warning: {}", e);
113→        }
114→    }
115→
116→    // Output JSON result
117→    let drafted_json: Vec<_> = result.drafted.iter().map(|m| {
118→        serde_json::json!({
119→            "old_coronet": m.old_coronet,
120→            "new_coronet": m.new_coronet,
121→            "silks": m.silks,
122→            "state": match m.state {
123→                jjrg_PaceState::Rough => "rough",
124→                jjrg_PaceState::Bridled => "bridled",
125→                jjrg_PaceState::Complete => "complete",
126→                jjrg_PaceState::Abandoned => "abandoned",
127→            },
128→            "spec": m.spec,
129→        })
130→    }).collect();
131→
132→    let output = serde_json::json!({
133→        "source": {
134→            "firemark": result.source_firemark,
135→            "silks": result.source_silks,
136→            "paddock": result.source_paddock,
137→            "empty_after": result.source_empty_after,
138→        },
139→        "destination": {
140→            "firemark": result.dest_firemark,
141→            "silks": result.dest_silks,
142→            "paddock": result.dest_paddock,
143→        },
144→        "drafted": drafted_json,
145→    });
146→
147→    match serde_json::to_string_pretty(&output) {
148→        Ok(json) => {
149→            let _ = writeln!(buf, "{}", json);
150→            (0, buf)
151→        }
152→        Err(e) => {
153→            eprintln!("jjx_restring: error serializing output: {}", e);
154→            (1, buf)
155→        }
156→    }
157→    // lock released here
158→}
