 5→//! Landing command - record agent landing after autonomous execution
 6→//!
 7→//! The landing command creates an empty commit recording when an autonomous agent
 8→//! completes execution of a bridled pace. The commit message uses the L (landing)
 9→//! marker in the steeplechase format.
10→
11→use clap::Args;
12→use crate::jjrf_favor::jjrf_Coronet as Coronet;
13→use crate::jjrn_notch::jjrn_format_landing_message;
14→
15→/// Arguments for jjx_landing command
16→#[derive(Args, Debug)]
17→pub struct jjrld_LandingArgs {
18→    /// Pace identity (Coronet)
19→    pub coronet: String,
20→
21→    /// Agent tier that executed the pace
22→    pub agent: String,
23→}
24→
25→/// Execute the landing command
26→///
27→/// Creates an empty commit with L marker recording when an agent completes
28→/// execution of a bridled pace. Content is the agent completion report.
29→///
30→/// Returns exit code (0 for success, non-zero for failure).
31→pub fn jjrld_run_landing(args: jjrld_LandingArgs, content: String) -> (i32, String) {
32→    let buf = String::new();
33→
34→    // Parse coronet
35→    let coronet = match Coronet::jjrf_parse(&args.coronet) {
36→        Ok(c) => c,
37→        Err(e) => {
38→            eprintln!("jjx_landing: error: {}", e);
39→            return (1, buf);
40→        }
41→    };
42→
43→    // Use jjrn_format_landing_message to create the commit message, with content as body
44→    let base_message = jjrn_format_landing_message(&coronet, &args.agent);
45→    let message = if content.trim().is_empty() {
46→        base_message
47→    } else {
48→        format!("{}\n\n{}", base_message, content.trim())
49→    };
50→
51→    // Create empty landing commit
52→    let commit_args = vvc::vvcc_CommitArgs {
53→        prefix: None,
54→        message: Some(message),
55→        allow_empty: true,
56→        no_stage: true,
57→        size_limit: vvc::VVCG_SIZE_LIMIT,
58→        warn_limit: vvc::VVCG_WARN_LIMIT,
59→    };
60→
61→    let rc = vvc::commit(&commit_args);
62→    (rc, buf)
63→}
