  5→//! jjx_retire command - Extract complete Heat data for archival trophy
  6→//!
  7→//! Handles retire operation: optionally dry-run (preview trophy) or execute
  8→//! (write trophy, remove from gallops, delete paddock, commit).
  9→
 10→use std::fmt::Write;
 11→use std::path::{Path, PathBuf};
 12→
 13→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 14→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_RetireArgs as LibRetireArgs};
 15→use crate::jjrs_steeplechase::{jjrs_ReinArgs as ReinArgs, jjrs_get_entries as get_entries};
 16→use crate::jjrc_core::jjrc_timestamp_date;
 17→use crate::jjrn_notch::{jjrn_format_heat_message, jjrn_HeatAction};
 18→
 19→/// Arguments for jjx_retire command
 20→#[derive(clap::Args, Debug)]
 21→pub struct jjrrt_RetireArgs {
 22→    /// Path to the Gallops JSON file
 23→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 24→    pub file: PathBuf,
 25→
 26→    /// Target Heat identity (Firemark)
 27→    pub firemark: String,
 28→
 29→    /// Execute the retire (write trophy, remove from gallops, delete paddock, commit)
 30→    #[arg(long)]
 31→    pub execute: bool,
 32→
 33→    /// Override size limit for commit guard (bytes)
 34→    #[arg(long)]
 35→    pub size_limit: Option<u64>,
 36→}
 37→
 38→/// Run the retire command
 39→pub fn jjrrt_run_retire(args: jjrrt_RetireArgs) -> (i32, String) {
 40→    use std::path::Path;
 41→
 42→    let mut buf = String::new();
 43→
 44→    let firemark = match Firemark::jjrf_parse(&args.firemark) {
 45→        Ok(fm) => fm,
 46→        Err(e) => {
 47→            eprintln!("jjx_retire: error: {}", e);
 48→            return (1, buf);
 49→        }
 50→    };
 51→
 52→    // Load gallops
 53→    let gallops = match Gallops::jjrg_load(&args.file) {
 54→        Ok(g) => g,
 55→        Err(e) => {
 56→            eprintln!("jjx_retire: error loading Gallops: {}", e);
 57→            return (1, buf);
 58→        }
 59→    };
 60→
 61→    // Get steeplechase entries (filtered by firemark identity)
 62→    let rein_args = ReinArgs {
 63→        firemark: args.firemark.clone(),
 64→        limit: 1000,
 65→    };
 66→    let steeplechase = match get_entries(&rein_args) {
 67→        Ok(entries) => entries,
 68→        Err(e) => {
 69→            eprintln!("jjx_retire: warning: could not get steeplechase: {}", e);
 70→            Vec::new()
 71→        }
 72→    };
 73→
 74→    // Compute base path from gallops file
 75→    let base_path = args.file.parent()
 76→        .and_then(|p| p.parent())
 77→        .and_then(|p| p.parent())
 78→        .unwrap_or(Path::new("."));
 79→
 80→    // If --execute not specified, output trophy markdown preview
 81→    if !args.execute {
 82→        // Read paddock content
 83→        let firemark_key = firemark.jjrf_display();
 84→        let heat = match gallops.heats.get(&firemark_key) {
 85→            Some(h) => h,
 86→            None => {
 87→                eprintln!("jjx_retire: error: Heat '{}' not found", firemark_key);
 88→                return (1, buf);
 89→            }
 90→        };
 91→        let paddock_path = base_path.join(&heat.paddock_file);
 92→        let paddock_content = match std::fs::read_to_string(&paddock_path) {
 93→            Ok(c) => c,
 94→            Err(e) => {
 95→                eprintln!("jjx_retire: error reading paddock: {}", e);
 96→                return (1, buf);
 97→            }
 98→        };
 99→
100→        // Build and output trophy preview
101→        let today = jjrc_timestamp_date();
102→        match gallops.jjrg_build_trophy_preview(&args.firemark, &paddock_content, &today, &steeplechase) {
103→            Ok(markdown) => {
104→                let _ = writeln!(buf, "{}", markdown);
105→                return (0, buf);
106→            }
107→            Err(e) => {
108→                eprintln!("jjx_retire: error: {}", e);
109→                return (1, buf);
110→            }
111→        }
112→    }
113→
114→    // --execute: perform the actual retire operation
115→
116→    // Need mutable gallops for execute path
117→    let mut gallops = gallops;
118→
119→    // Acquire lock FIRST
120→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
121→        Ok(l) => l,
122→        Err(e) => {
123→            eprintln!("jjx_retire: error: {}", e);
124→            return (1, buf);
125→        }
126→    };
127→
128→    // Execute retire
129→    let retire_args = LibRetireArgs {
130→        firemark: args.firemark.clone(),
131→        today: jjrc_timestamp_date(),
132→    };
133→
134→    let result = match gallops.jjrg_retire(retire_args, base_path, &steeplechase) {
135→        Ok(r) => r,
136→        Err(e) => {
137→            eprintln!("jjx_retire: error: {}", e);
138→            return (1, buf);
139→        }
140→    };
141→
142→    // Save gallops
143→    if let Err(e) = gallops.jjrg_save(&args.file) {
144→        eprintln!("jjx_retire: error saving Gallops: {}", e);
145→        return (1, buf);
146→    }
147→
148→    // Commit using vvcm_commit with explicit file list
149→    // Files: gallops.json, trophy file (created), paddock file (deleted - git add handles this)
150→    let gallops_path = args.file.to_string_lossy().to_string();
151→    let effective_size_limit = args.size_limit.unwrap_or(200000);
152→    let commit_args = vvc::vvcm_CommitArgs {
153→        files: vec![
154→            gallops_path,
155→            result.trophy_path.clone(),
156→            result.paddock_path.clone(),
157→        ],
158→        message: jjrn_format_heat_message(&firemark, jjrn_HeatAction::Retire, &result.silks),
159→        size_limit: effective_size_limit,
160→        warn_limit: effective_size_limit / 2,
161→    };
162→
163→    match vvc::machine_commit(&lock, &commit_args) {
164→        Ok(hash) => {
165→            eprintln!("jjx_retire: committed {}", &hash[..8]);
166→        }
167→        Err(e) => {
168→            eprintln!("jjx_retire: error: commit failed: {}", e);
169→            // Rollback: restore gallops and paddock from HEAD, remove trophy
170→            let gp = args.file.to_string_lossy().to_string();
171→            let _ = std::process::Command::new("git")
172→                .args(["checkout", "HEAD", "--", &gp, &result.paddock_path])
173→                .status();
174→            let _ = std::process::Command::new("git")
175→                .args(["rm", "-f", "--cached", &result.trophy_path])
176→                .status();
177→            let _ = std::fs::remove_file(&result.trophy_path);
178→            eprintln!("jjx_retire: rolled back file changes");
179→            eprintln!("jjx_retire: retry with --size-limit <bytes> to override guard");
180→            return (1, buf);
181→        }
182→    }
183→
184→    // Output result
185→    let _ = writeln!(buf, "trophy: {}", result.trophy_path);
186→    let _ = writeln!(buf, "Heat {} retired successfully", result.firemark);
187→
188→    (0, buf)
189→    // lock released here
190→}
191→

